var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"이야, 깜짝 놀랐습니다.","JPN":"いやあ、ビックリしたっすよ。","ENG":"Whoa, that startled me.","TWN":"哎呀，嚇死我了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"바다 한복판이 번쩍 하더니, 거기서 사람이 떨어질 거라곤 꿈에도 몰랐거든요.","JPN":"海のど真ん中がピカーっと光ったと思ったら、人が落ちてきたっしょ？　そんなこと夢にも思わねぇっすから。","ENG":"The sea suddenly flashed out in the middle of nowhere, and I never imagined people would come falling out of it.","TWN":"海中央突然有閃光，作夢都沒想到會有人從裡面掉下來。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"마침 배가 근처에 있어서 살았어요. 저희 중 한 명이 수영을 전혀 못 하거든요.","JPN":"ちょうど近くに船があって助かったよ。一人、全然泳げない人がいたから。","ENG":"Lucky for us your boat was nearby. One of us can't swim at all.","TWN":"我們之中有人完全不會游泳，幸好船就在附近才得救。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"말했다시피 우린 훈련 중인 카운터다. 이 녀석의 공간이동 능력을 함께 시험하다 이렇게 됐지.","JPN":"さっきも話したように、私たちは訓練中のカウンターだ。こいつの空間移動能力をテストしていたらこうなった。","ENG":"Like I said, we're Counters in training. We were testing this one's teleportation ability together when it happened.","TWN":"就像之前說的，我們是在訓練中的制裁者。在測試這傢伙的空間移動能力時才變成這樣。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 제가요?","JPN":"え？　私ですか？","ENG":"Huh? Me?","TWN":"欸？我嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으악! 네, 넵! 전 공간이동 능력을 쓰는 카운터 훈련생입니닷! 제 실력이 미흡해서 시민 분께 신세를 졌습니다!","JPN":"わあっ！　は、はい！　私は空間移動能力を使うカウンター訓練生です！　私の実力が足りなくて、市民の方にご迷惑をおかけしました！","ENG":"Aah! O-okay! I'm a Counter trainee with teleportation abilities! My skills weren't up to par, so we ended up troubling a civilian!","TWN":"啊！是、是的！我是使用空間移動能力的制裁者訓練生！因為我實力不足，才會麻煩您！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"공간이동이라니 신기하네요. 능력을 쓸 때는 특별한 포즈 같은 거라도 취하나요?","JPN":"空間移動なんて不思議っすね。能力を使う時には、特別なポーズを取ったりするんすか？","ENG":"Teleportation, huh? That's amazing. Do you strike some kind of special pose when you use it?","TWN":"空間移動啊，真神奇。使用能力時會擺什麼特別姿勢嗎？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"네? 어... 음...","JPN":"えっ？　あ……えーっと……","ENG":"Huh? Uh... um...","TWN":"欸？呃……嗯……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이렇게, 눈을 감고 정신을 집중하면서...","JPN":"こうやって、目を閉じて精神を集中しながら……","ENG":"Like this, I close my eyes and focus...","TWN":"像這樣，閉上眼睛集中精神……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"두 손가락을 펼쳐 이마 중심을 가리킵니다!","JPN":"指を伸ばして額の中心に当てます！","ENG":"Then put two fingers at the center of my forehead!","TWN":"然後伸出兩根手指，指向額頭中央！"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"오, 그럴싸 한데?","JPN":"おお、それっぽい。","ENG":"Oh, that actually looks convincing.","TWN":"哦，挺像回事的呢？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_TOUCH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"하하, 멋지기 보단 귀엽네요.","JPN":"はは、カッコいいというより可愛いっすね。","ENG":"Haha, more cute than cool.","TWN":"哈哈，比起帥氣更可愛呢。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"생각보다 어린 친구들이라 놀랐어요. 뉴스로 소식은 들었는데, 초능력자들이 우리 사회에 그렇게 많았다는 사실이 아직은 좀 낯설기도 하고요.","JPN":"それにしても、思ったより若くてビックリしたっすよ。ニュースで聞いてはいたけど、超能力者がこの社会にそんなに多かったなんて、まだ実感が湧かねぇっす。","ENG":"I'm surprised you're younger than I expected. I heard about it on the news, but it's still a little strange getting used to the fact that there are so many people with superpowers in our society.","TWN":"沒想到你們這麼年輕。雖然新聞有報導，但還是不太習慣社會上有這麼多超能力者。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"여러분도 다른 카운터 분들처럼 관리국에 들어가기 위해 훈련하고 계신 거죠?","JPN":"皆さんも他のカウンターみたく管理局に入るために訓練してるんすよね？","ENG":"You're training to join the Administration like the other Counters, right?","TWN":"你們也像其他制裁者一樣，為了進入管理局在訓練吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 마침 오늘 그라운드 원에 공인 선발 시험이 있어서 하루 묵을 알아보던 중이었다.","JPN":"ああ。ちょうど今日グラウンド・ワンで公認選抜試験があって、一晩泊れるところを探していたんだ。","ENG":"That's right. There was an official audition at Ground One today, so we were looking for somewhere to stay the night.","TWN":"對。剛好今天在G1有正式選拔考試，我們正打算找地方住一晚。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그라운드 원... 그렇죠. 벌써 다들 그런 이름으로 부르는군요.","JPN":"グラウンド・ワン……そうっすか。もうみんなその名前で呼んでるんすね。","ENG":"Ground One... right. Everyone's already calling it that.","TWN":"G1啊……也對，現在大家都這麼叫了呢。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"하긴, 저 대균열이라는 것이 도시를 집어삼킨 뒤로는 완전히 다른 곳이 됐으니까요.","JPN":"まあ、あの大亀裂っちゅうのが都市を飲み込んでからは、完全に別の場所になっちまったっすから。","ENG":"Well, once that Grand Dimension Crevice swallowed up the city, it really did become a completely different place.","TWN":"畢竟自從大峽谷吞噬城市之後，這裡已經完全變成另一個地方了。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L31_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그래도 다행이에요.","JPN":"でも、よかったっす。","ENG":"Still, it's a relief.","TWN":"不過真是萬幸。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"그땐 세상이 다 끝나는 줄 알았는데, 관리국 덕에 다시 사람이 살 수 있는 곳이 되어가고 있다는 게 느껴지거든요.","JPN":"当時は世界が終わると思ったっすけど、管理局のおかげでまただんだん人が住める場所になっている気がするっすよ。","ENG":"Back then, I thought the world was over, but thanks to the Administration, it feels like it's becoming a place people can live in again.","TWN":"當時我以為世界真的要滅亡了。但現在我能感覺到在管理局的努力下，這裡正重新變成能讓人生活的地方。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"아마... 이런 식으로 20년 정도만 지나면, 아무 걱정 없던 다시 원래의 삶으로 돌아가 있겠죠?","JPN":"たぶん……こんな感じで20年くらい経てば、何の心配もなかった元の生活に戻れるんじゃないっすかね。","ENG":"Maybe... if another twenty years pass like this, we'll be back to our old lives without a single worry, don't you think?","TWN":"大概……再過20年左右，大家就能回到以前那種毫無煩惱的生活吧？"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어... 그건...","JPN":"え……それは……","ENG":"Uh... well...","TWN":"呃……那個……"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응, 그럴 거야.","JPN":"うん、そうだよ。","ENG":"Yeah, us too.","TWN":"嗯，一定會的。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"우리가 그렇게 되도록 만들 테니까.","JPN":"私たちがそうなるようにするから。","ENG":"We'll make sure it happens.","TWN":"我們會讓它實現。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"...고마워요. 든든하네요.","JPN":"……ありがてえ。心強いっす。","ENG":"...Thank you. That's reassuring.","TWN":"……謝謝，聽你這麼說真讓人安心。"},"stage":{"bg":"FRONTBAY_DECK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"여기서 좀 더 가시면 관리국에서 마련한 캠프가 있습니다.","JPN":"ここからもう少し行ったところに、管理局が建てたキャンプがあるっす。","ENG":"If you go a little farther from here, there's a camp the Administration set up.","TWN":"再往前走一點，就有管理局設立的營地。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FISHER_NPC_NULL_NULL","text":{"KOREA":"호텔은 아니지만, 하루 묵어가기엔 부담 없을 거에요. 관리국 직원 분들도 많이 계시거든요.","JPN":"ホテルじゃないが、一晩泊るには問題ないはずっす。管理局職員もたくさんいるし。","ENG":"It's not a hotel, but it's a fine place to stay for a night. There are plenty of Administration staff there too.","TWN":"雖然不是飯店，但住一晚沒問題。那裡也有很多管理局的人。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"여기까지 안내해줘서 고마워, 아저씨.","JPN":"ここまで案内してくれてありがとう、おじさん。","ENG":"Thanks for showing us the way, mister.","TWN":"謝謝你帶我們到這裡，大叔。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"공간이동 능력자 노엘! 도와주신 선생님께 감사를 표합니다!","JPN":"空間移動能力者のノエル！　助けていただき感謝いたします！","ENG":"Noelle the teleporter expresses her gratitude to the gentleman who helped us!","TWN":"空間移動能力者洛艾兒！向幫助我們的老師致謝！"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L48_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"공간이동 능력자는 이제 그만 붙여도 돼.","JPN":"空間移動能力者って言葉、もうつけなくていいから。","ENG":"You can stop adding \\"teleporter\\" now.","TWN":"不用再強調空間移動能力者了。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그나저나 이제 어디로 가야 하지?","JPN":"それより、これからどこに行く？","ENG":"Anyway, where do we go from here?","TWN":"話說回來，我們現在要去哪裡？"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"여기다.","JPN":"ここだ。","ENG":"Here.","TWN":"就是這裡。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 캠프에 우리가 만날 사람이 있어.","JPN":"このキャンプに探し人がいる。","ENG":"There's someone in this camp we need to meet.","TWN":"這個營地有我們要見的人。"},"stage":{"bg":"DOCK_DAY","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"subtitle","speaker":null,"text":{"KOREA":"그라운드 원, 관리국 캠프. 직원 임시주거 단지","JPN":"グラウンド・ワン、管理局キャンプ。職員臨時住居団地","ENG":"Ground One, Administration Camp. Staff Temporary Housing Complex","TWN":"G1，管理局營地。員工臨時居住區"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"죄송하지만 오늘은 이만 돌아가시는 게 좋겠습니다.","JPN":"すみません、今日はお引き取りください。","ENG":"I'm sorry, but I think it would be best if you headed back for today.","TWN":"不好意思，今天請先回去吧。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"아무리 카운터라고 하셔도, 저희 측 기술자 분들을 그렇게 마음대로 만나실 순 없어요.","JPN":"いくらカウンターだとおっしゃいましても、そう簡単にこちらの技術者と会わせるわけにはいきませんよ。","ENG":"No matter if you're Counters, you can't just meet our engineers whenever you feel like it.","TWN":"就算是制裁者，也不能隨便見我們這邊的技術人員。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"펜릴 소대의 힐데가 찾아왔다고 전해라.","JPN":"フェンリル小隊のヒルデが来たと伝えてくれ。","ENG":"Tell him Hilde of the Fenrir Squad has come looking for him.","TWN":"就說芬里爾小隊的希爾德來了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우릴 만날지 말지는 그 녀석의 판단에 맡기라고 해.","JPN":"私たちに会うかどうかは、そいつの判断に任せると。","ENG":"And say whether he meets us or not is up to him.","TWN":"讓那傢伙自己決定要不要見我們。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"...음.","JPN":"……ふむ。","ENG":"...Hmm.","TWN":"……嗯。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"EMPLOYEE_CHARADE_NULL_ADMIN","text":{"KOREA":"어쩔 수 없죠. 그렇게 전달만 해두겠습니다.","JPN":"仕方ありませんね。そう伝えてはおきます。","ENG":"All right. I'll at least pass the message along.","TWN":"沒辦法了，我只會幫你們這樣轉達。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EMPLOYEE_CHARADE_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"근데 소대장, 이렇게 막 이름을 밝혀도 괜찮은 거야?","JPN":"でも小隊長、簡単に名前を出しちゃって大丈夫なの？","ENG":"But Commander, is it really okay to just reveal your name like that?","TWN":"不過小隊長，直接報名字真的沒問題嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나하고 노엘이야 그럴 일이 없겠지만, 과거의 소대장을 실수로 만나게 될 수도 있는 거잖아.","JPN":"私とノエルはそんなことないけど、過去の小隊長にうっかり出会うことになるかもしれないし。","ENG":"It probably won't happen with me or Noelle, but you could still accidentally run into your past self.","TWN":"我跟洛艾兒當然不會有問題，但說不定會碰到過去的小隊長本人啊。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"걱정 마라. 내가 날 만날 일은 없을 테니까.","JPN":"心配するな。私が自分に出会うことはない。","ENG":"Don't worry. I won't be meeting myself.","TWN":"放心吧，我不會遇到我自己的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"너희 둘은 잠깐 여기서 기다리도록.","JPN":"二人はここで待っていろ。","ENG":"You two wait here for a moment.","TWN":"你們兩個先在這裡等一下。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"...이유는 설명도 안 해주고 가버리네.","JPN":"……理由も言わないで行っちゃった。","ENG":"...She just left without explaining why.","TWN":"……什麼都沒解釋就走了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐, 괜찮다니까 다행이지만.","JPN":"まあ、大丈夫ならいいけどさ。","ENG":"Well, if she says it's fine, I guess that's a relief.","TWN":"算了，既然說沒問題就好。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"혹시... 사장님께선 여기까지도 안배해두신 게 아닐까요?","JPN":"もしかして……社長はここまで準備しておいたんじゃないでしょうか？","ENG":"Do you think... maybe the Boss arranged even this?","TWN":"說不定……老闆連這一步都安排好了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"이 시간의 힐데 소대장님이 미래에서 온 자신과 마주치지 않도록, 아무 활동도 하지 않고 조용히 잠적하게 해뒀다거나.","JPN":"この時代のヒルデ小隊長が未来から来た自分と出くわすことのないように、何の活動もせずに静かに潜んいるようにしたとか。","ENG":"Like making sure Commander Hilde of this era quietly disappeared without doing anything, so she wouldn't run into the future version of herself.","TWN":"為了避免這個時間的希爾德小隊長遇到來自未來的自己，所以讓她什麼都不做、靜靜潛伏之類的。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"말도 안되는 것 같으면서도... 사장님이라면 그럴 수 있겠다는 생각이 드네.","JPN":"あり得ないようでいて……社長ならやりかねないかも。","ENG":"It sounds impossible... but with Boss, I can kind of believe it.","TWN":"雖然聽起來很離譜……但如果是老闆，好像也有可能會這麼做。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그쵸?","JPN":"でしょう？","ENG":"Right?","TWN":"對吧？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_QM","text":{"KOREA":"실례합니다만,","JPN":"失礼ですが、","ENG":"Excuse me,","TWN":"不好意思。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_QM","text":{"KOREA":"그 문장은 관리국 전대의 표식인데, 어째서 당신이 그걸 갖고 있는 거죠?","JPN":"その紋章は管理局戦隊の標識ですよね。どうしてあなたがそれを持っているんですか？","ENG":"That crest is the mark of an Administration Division. Why do you have it?","TWN":"那個紋章是管理局前代的標記，為什麼會在你身上？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"응? 어째서냐니, 그야...","JPN":"え？　どうしてって、そりゃ……","ENG":"Huh? Why do I have it? Well, that's...","TWN":"嗯？哪有什麼為什麼，那是……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗...!","JPN":"あっ……！","ENG":"Ah...!","TWN":"啊……！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"마왕이다!","JPN":"魔王だ！","ENG":"It's a Demon Lord!","TWN":"是魔王！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"마왕이요? 제가 말인가요?","JPN":"魔王？　僕がですか？","ENG":"A Demon Lord? Me?","TWN":"魔王？是在說我嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"...나유빈?","JPN":"……イチノセ・カオル？","ENG":"...Na Yubin?","TWN":"……羅瑜斌？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"당신이 제 이름을 어떻게...?","JPN":"あなたがどうして僕の名前を……？","ENG":"How do you know my name...?","TWN":"你怎麼會知道我的名字……？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"두 분은 신원 조회가 필요하겠네요. 잠시 저와 동행해주셔야겠습니다.","JPN":"お二人とも身元確認が必要そうですね。しばしご同行願えますか。","ENG":"You two will need an identity check. I'll have to ask you to come with me for a moment.","TWN":"你們兩位需要進行身分查驗，請跟我走一趟。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"조회할 것도 없어. 저 둘은 펜릴 전대의 신참들이다.","JPN":"確認する必要はない。その二人はフェンリル戦隊の新人だ。","ENG":"There's nothing to check. Those two are rookies from Fenrir Squad.","TWN":"不用查了，那兩個是芬里爾戰隊的新人。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"네 후배들이지.","JPN":"お前の後輩になる。","ENG":"They are your juniors.","TWN":"是你的後輩。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"...스승님?","JPN":"……師匠？","ENG":"...Master?","TWN":"……師父？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"왜 지금 와서...","JPN":"なんで今更……","ENG":"Why are you only showing up now...?","TWN":"為什麼現在才……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"대체 지금까지 어디로 사라지셨던 거에요? 그동안 수연이가 스승님을 얼마나...!!","JPN":"いったい今までどこにいたんですか？　キズナが師匠をどれだけ……！！","ENG":"Where in the world have you been all this time? Do you know how much Sooyeon has–!!","TWN":"這段時間到底去哪裡了？秀妍她這段時間有多擔心老師……！！"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이수연은 지금쯤 재활을 끝내고 파견을 떠났겠군.","JPN":"キズナなら、今頃リハビリが終わって派遣に出てる頃だな。","ENG":"By now, Lee Sooyeon should have finished rehab and left on deployment.","TWN":"李秀妍現在應該已經結束復健，被派遣出去了。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"급한 사안이 있어서 잠시 돌아왔을 뿐이니, 그 녀석에겐 연락하지 말도록.","JPN":"急用があって一時的に戻ってきただけだ。あいつには連絡するな。","ENG":"I only came back for a pressing matter, so don't contact her.","TWN":"我只是有急事暫時回來，不要通知她。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"다 알고 계셨습니까?","JPN":"全部ご存じだったんですか？","ENG":"So you knew all along?","TWN":"您都知道嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 저흴 다 지켜보면서도 소식 한 번 들려주지 않으신 건가요?","JPN":"そうやって僕たちを見守っていたのに、何も話してくれなかったんですか？","ENG":"You were watching over all of us, and still never let us hear a word from you?","TWN":"那您明明一直看著我們，卻連一點消息都不告訴我們嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"어리광은 그쯤 해둬라. 긴급한 사안이라고 했을 텐데?","JPN":"駄々をこねるのもいい加減にしろ。急用だと言ったはずだ。","ENG":"That's enough whining. I said it was urgent, didn't I?","TWN":"別撒嬌了，我不是說了是急事嗎？"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L1_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L2_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"알겠습니다. 용무를 말씀하시죠.","JPN":"分かりました。用件をどうぞ。","ENG":"Understood. Tell me what you need.","TWN":"我明白了。請說明來意。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주한과 연화. 그 둘을 만나러 왔다.","JPN":"シスイとレンカ。その二人に会いに来た。","ENG":"I came to see Joo Han and Yeonhwa.","TWN":"我們來找周翰和蓮華。"},"stage":{"bg":"CAMP_01","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"스승님!","JPN":"師匠！","ENG":"Master!","TWN":"師父！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앗, 제자의 포옹을 피했어. 너무하세요!","JPN":"あっ、弟子の抱擁をかわすなんて。ひどいです！","ENG":"Ah, you dodged your apprentice's hug. That's so mean!","TWN":"啊，居然躲開徒弟的擁抱。太過分了！"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"얼마 안 봤다고 그새 버르장머리가 없어졌군.","JPN":"少し見ない間に行儀が悪くなったな。","ENG":"I haven't seen you in that long, and already your manners are gone.","TWN":"才多久沒見，你就變得這麼沒規矩。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주한에게 이걸 전해줘라.","JPN":"シスイにこれを渡してくれ。","ENG":"Give this to Joo Han.","TWN":"把這個交給周翰。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이건... 청사진이네요.","JPN":"これは……青写真ですね。","ENG":"This is... a blueprint.","TWN":"這是……設計圖。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우.물</color>? 이게 무슨 뜻이죠?","JPN":"<color=#ffd34c>イ・ド</color>？　これってどういう意味ですか？","ENG":"<color=#ffd34c>Well</color>? What does that mean?","TWN":"<color=#ffd34c>井</color>？這是什麼意思？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"우리의 염원을 이뤄줄 물건... 이라더군.","JPN":"いつか願いを叶えてくれる道具……らしいな。","ENG":"Wish-Enabling... Lasting Legacy... or so I heard.","TWN":"據說是能實現我們願望的……東西。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"아니, 다른 줄임말이었나? 어쨌든 맥락은 비슷할 거다.","JPN":"いや、違ったか？　とにかく似たような趣旨だったはずだ。","ENG":"No, maybe it stood for something else. Either way, the idea is probably similar.","TWN":"還是這是其他詞彙的縮寫？反正脈絡差不多。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"주한 씨랑 무척 비슷한 작명법이네요.","JPN":"シスイさんの命名法にとてもよく似ていますね。","ENG":"That naming style sounds a lot like Joo Han's.","TWN":"這命名方式跟周翰先生還真像。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...그래.","JPN":"……ああ。","ENG":"...Yeah.","TWN":"……嗯。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"혹시... 그 사람이랑 이게 무슨 연관이 있는 건가요?","JPN":"もしかして……あの人とこれは何か関係があるのですか？","ENG":"Could it be... does this have something to do with him?","TWN":"難道……這跟那個人有關嗎？"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"물론 연관이 있지.","JPN":"もちろん関係がある。","ENG":"Of course it does.","TWN":"當然有囉。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"적어도 이곳에선, 이 설계도를 이해할 수 있는 기술자는 주한 뿐일 테니까.","JPN":"少なくともここでは、この設計図を理解できる技術者はシスイしかいないからな。","ENG":"At least here, Joo Han is the only technician who can understand this design.","TWN":"至少在這裡，能理解這份設計圖的技術人員只有周翰。"},"stage":{"bg":"FACILITY","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"주한- 또 여기서 자고 있어?","JPN":"シスイ～またここで寝てるの？","ENG":"Joo Han, you fell asleep in here again?","TWN":"周翰—又睡在這裡了嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"으음...?","JPN":"うーん……？","ENG":"Mm...?","TWN":"嗯……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"으이구, 서생아. 또 독서하느라 밤샜구나?","JPN":"もう、この書生め。また夜明けまで読書してたわね？","ENG":"Good grief, Seosaeng. Were you up all night reading again?","TWN":"哎呀，書生啊，又熬夜讀書了吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"미안해요. 그런데 이건 독서가 아니라...","JPN":"すいません。でも、これは読書じゃなくて……","ENG":"Sorry. But this isn't reading, it's...","TWN":"抱歉，不過我不是在讀書……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"...문헌 연구, 맞지?","JPN":"……文献の研究、でしょう？","ENG":"...Document research, right?","TWN":"……是文獻研究，對吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"쓸데없는 변명하지 말고. 중요한 손님이 오셨으니 인사나 드려.","JPN":"言い訳なんてしてないで。大事なお客さんがいらしてるから、挨拶して。","ENG":"Save the pointless excuses. We have an important guest, so at least say hello.","TWN":"別找那些沒用的藉口了。有重要的客人來了，先打聲招呼吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"중요한 손님...?","JPN":"大事なお客さん……？","ENG":"An important guest...?","TWN":"重要的客人……？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"스승님? 돌아오셨네요?","JPN":"師匠？　お戻りになったんですか？","ENG":"Master? You're back?","TWN":"師父？您回來了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"검 하나 못 휘두르는 녀석이 누구더러 스승이냐.","JPN":"剣も振るえないくせに、何が師匠だ。","ENG":"A man who can't even swing a sword has no business calling me Master.","TWN":"連劍都揮不好的人，還叫我師父？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"연화 씨의 스승님이니 저한테도 마찬가지죠.","JPN":"レンカさんの師匠ですから、俺にとっても同じようなものです。","ENG":"You're Yeonhwa's master, so that makes you mine too.","TWN":"既然是蓮華小姐的師父，也就是我的師父。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그리고, 연화 씨의 비밀 대해 많은 걸 가르쳐주시기도 했고요.","JPN":"それに、レンカさんの秘密についてたくさん教えてもらいましたし。","ENG":"And you've taught me a great deal about Yeonhwa's secret as well.","TWN":"而且您也教了我很多有關蓮華的祕密。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"가르쳐준 게 아니라 주의를 줬을 뿐이다.","JPN":"教えたわけではなく、注意しただけだ。","ENG":"I didn't teach you anything. I merely warned you.","TWN":"我不是教你，只是提醒你而已。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"넌 그 주의를 전부 무시했으니 나에게 배운 것도 하나 없는 셈이지.","JPN":"お前はそれを全部無視したから、私から教わったことなど何もない。","ENG":"And since you ignored every one of those warnings, that means you learned nothing from me.","TWN":"但你竟然無視所有提醒，等於什麼都沒從我這裡學到。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"무시가 아니에요. 전부 감내하기로 했을 뿐인 걸요.","JPN":"無視したわけではありません。全部甘受することにしただけですよ。","ENG":"I didn't ignore them. I simply chose to bear them all.","TWN":"我不是無視，只是決定承受一切而已。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...멍청한 녀석.","JPN":"……バカが。","ENG":"...You fool.","TWN":"……笨蛋。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"음... 구조는 거의 이해했어요.","JPN":"うーん……構造はだいたい理解しました。","ENG":"Hmm... I understand most of the structure now.","TWN":"嗯……結構我大致理解了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"잠깐 훑어본 것 뿐인데 벌써? 전부 다 파악했다고?","JPN":"ざっと見ただけなのに、もう？　全部把握したの？","ENG":"You just skimmed it and already? You figured the whole thing out?","TWN":"才稍微看了一下而已？這麼快就全弄懂了？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"저도 이런 비슷한 걸 구상하다가 결국 포기했었거든요. 누구나 타임머신에 대한 꿈은 꾸잖아요.","JPN":"俺もこれと似たようなものを構想してたんですが、結局形にならなかったんです。誰でもタイムマシンには憧れますからね。","ENG":"I actually tried coming up with something similar once, but eventually gave up. Everyone dreams of a time machine, don't they?","TWN":"其實我以前也有過類似的構想，不過最後放棄了。畢竟誰都有做過關於時光機的夢嘛。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이해가 안되는 게 있다면... 이 설명조차 없는 동력원 <color=#ffd34c>X</color>에 대한 건데.","JPN":"理解できない部分があるとすれば……この説明すらない動力源<color=#ffd34c>X</color>についてですが。","ENG":"If there's one thing I don't understand... it's this power source <color=#ffd34c>X</color> that isn't explained at all.","TWN":"如果說有看不懂的地方……大概就是這個連說明都沒有的動力源<color=#ffd34c>X</color>。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"아, 걱정 마세요. 동력원 X는 저희가 조달할 테니까요.","JPN":"あ、心配しないでください。動力源Xは私たちが調達しますので。","ENG":"Ah, don't worry. We'll procure power source X ourselves.","TWN":"不用擔心，我們會準備動力源X。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"주의! 절대로 이것의 정체에 대해 의문을 품게 하지 말 것!","JPN":"注意！　絶対この正体について疑問を抱かせないこと！","ENG":"Warning! Under no circumstances should you become curious about what this really is!","TWN":"注意！絕對不要對它的真實身分產生疑問！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그 부분까지는 안 읽어도 돼, 노엘.","JPN":"そこまで読まなくてもいいよ、ノエル。","ENG":"You don't have to read that part out loud too, Noelle.","TWN":"不用讀到那部分也沒關係，洛艾兒。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그렇다고 하니 그런 줄 알겠습니다만-","JPN":"まあそう言うならそれでいいですが……","ENG":"If you say so, then I'll leave it at that...","TWN":"既然都這麼說了，我就先這麼理解—"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이거... 정보 오염과 관련된 내용 맞죠? 스승님?","JPN":"これ……情報汚染と関係のある内容ですよね？　師匠。","ENG":"But this... has to do with information contamination, doesn't it, Master?","TWN":"但這個……應該和資訊污染有關吧，師父？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그래. 알려고 하면 다칠 거다. 세계침식률에 큰 영향을 초래하겠지.","JPN":"ああ。詮索しない方がいい。世界侵食率に大きな影響を及ぼすことになるだろう。","ENG":"Yes. You'll get hurt if you try to know more. It would have a major impact on the Global Corruption Rate.","TWN":"沒錯。如果試圖瞭解就會受傷，還會對世界侵蝕率造成很大的影響。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"...이해했습니다.","JPN":"……分かりました。","ENG":"...Understood.","TWN":"……我明白了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"안 그래도 기술지휘부 측에서 곧 중요한 작업이 있을 거라고 하던데.","JPN":"そういえば、技術指揮部のほうでもうすぐ重要な作業があると言ってましたが。","ENG":"I'd already heard the technical command division would soon be carrying out something important.","TWN":"剛好技術指揮部那邊也說很快就會有重要任務。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이거, 아무래도 관리국의 높은 분까지 엮일 만큼 큰일인 모양이죠?","JPN":"これって、管理局のお偉方まで関わってくるぐらいの大事件みたいですね？","ENG":"This must be a major matter, if it's serious enough to involve even the higher-ups in the Administration, right?","TWN":"看來這件事大到牽扯進管理局高層了吧？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"과학자 말고 차라리 탐정을 하지 그랬냐?","JPN":"科学者より探偵のほうがよっぽど向いてるのではないか？","ENG":"Why don't you become a detective instead of a scientist?","TWN":"你不要當科學家，乾脆去當偵探算了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"하하, 너무하세요. 탐정 일을 하면 연화 씨를 못 만나게 되잖아요.","JPN":"はは、ひどいなあ。探偵の仕事をしたらレンカさんに会えなくなるじゃないですか。","ENG":"Haha, that's harsh. If I became a detective, I wouldn't be able to see Yeonhwa.","TWN":"哈哈，太過分了。要是當偵探，我就見不到蓮華了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"기간은 얼마나 걸리지?","JPN":"どれくらいかかる？","ENG":"How long will it take?","TWN":"需要多久時間？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"그게 문제인데, 이해와 실용은 조금 차이가 있어서요.","JPN":"そこが問題なんですが、理解するのと実用するのには若干違いがありますからね。","ENG":"That's the problem. Understanding it and putting it into practice are a little different.","TWN":"問題就在這裡，理解和實際製作還是有點差距。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이 설계도만 가지고 완전히 똑같이 모방하려면... 6개월 정도는 걸리겠어요.","JPN":"この設計図だけで完璧に模倣するには……6か月程かかると思います。","ENG":"If I had to reproduce this exactly from the blueprint alone... it would take about six months.","TWN":"如果只靠這張設計圖完全複製……大概要6個月。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"6개월씩이나?!","JPN":"6か月も！？","ENG":"Six months?!","TWN":"6個月？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"말도 안돼! 우리가 여기 머물 수 있는 시간은 보름이 최대일 거랬는데?!","JPN":"そんな！　私たちがここに居られる時間は最大15日なのに！？","ENG":"No way! We were told the longest we can stay here is two weeks!","TWN":"這樣不行！我們能在這裡停留的時間最多只有半個月啊？！"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"만약, 이것을 직접 설계한 사람과 함께 작업한다면 얼마나 단축되지?","JPN":"もし、これを設計した本人と一緒に作業するならどれくらい短縮できる？","ENG":"If you worked together with the person who designed this, how much could you shorten that?","TWN":"如果和設計這個裝置的人一起製作，能縮短多少時間？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"설계를 이해하고 있다면, 한 달로도 충분하겠죠.","JPN":"設計を理解しているのなら、1か月で十分でしょう。","ENG":"If that person understands the design, one month should be enough.","TWN":"只要理解設計的話，一個月就足夠了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"다만, 일회성이란 점을 고려해 설계자의 도움을 받아 약식으로 제작한다면... 그보다 시일을 단축할 수도 있을 거에요.","JPN":"ただ、使い捨てという点を考慮し、設計者の協力を得て略式で製作するなら……それよりも短くできるかもしれません。","ENG":"Though, considering it's only meant for one-time use, if we build a simplified version with the designer's help... we could probably shorten the schedule even more.","TWN":"不過如果考慮到這只使用一次，如果在設計者的幫助下簡化製作流程……也許還能再縮短一些時間。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"...알겠다.","JPN":"……分かった。","ENG":"...I see.","TWN":"……我知道了。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그럼, 데려오도록 하지.","JPN":"では、連れてくるとしよう。","ENG":"Then I'll bring him here.","TWN":"那就把它帶來吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"자.","JPN":"こいつだ。","ENG":"Here.","TWN":"來。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이건... 사람이 아니라 기계네요.","JPN":"これは……人ではなく、機械ですね。","ENG":"This is... a machine, not a person.","TWN":"這是……不是人，而是機械。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"소대장님이 아까 어딜 다녀온다고 하면서 가져오신 게 이거였어요?","JPN":"小隊長がさっき出掛けてくると言われたのは、これを持ってくるためだったんですか？","ENG":"Is this what Commander brought back when she said she had somewhere to go earlier?","TWN":"剛才小隊長說要去辦點事，帶回來的就是這個嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"사장님의 머신갑이랑 똑같이 생겼네.","JPN":"社長のマシーン甲とそっくり。","ENG":"It looks exactly like the Boss's Machine G.A.P.","TWN":"看起來跟老闆的機械甲一模一樣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"주한, 이 테라브레인에 이걸 설치해봐라.","JPN":"シスイ、このテラブレインにこれをインストールしてみろ。","ENG":"Joo Han, install this into this Terrabrain.","TWN":"周翰，把這個裝到特拉大腦。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"이건... 기억 카트리지군요.","JPN":"これは……記憶カートリッジですね。","ENG":"This is... a memory cartridge.","TWN":"這是……記憶卡匣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"잠시만 기다려주세요.","JPN":"少しお待ちください。","ENG":"Just give me a moment.","TWN":"請稍等一下。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_TOUCH"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L30_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...반갑소. 난 관리국의 수석기술자인 하담이라 하네.","JPN":"……お初にお目にかかる。某は管理局の首席技術者、カタンと申す。","ENG":"...A pleasure to meet you. I am Ha Dam, the Administration's chief engineer.","TWN":"……很高興見到你們。我是管理局的首席技術人員，夏垣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"아, 네. 반갑습니다. 하담 씨.","JPN":"あ、はい。はじめまして、カタンさん。","ENG":"Ah, yes. Nice to meet you, Ha Dam.","TWN":"啊，是。很高興見到你，夏垣。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"지금부터 본인이 우물의 제작 공정을 거들도록 하지.","JPN":"今から某がイドの製作工程を手伝うとしよう。","ENG":"From this point on, I shall assist with the Well's construction process.","TWN":"接下來我會協助進行井的製作工序。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"설치 장소가 침식지대에 자리해 있을 테니, 전투원들을 대동해주게.","JPN":"設置する場所は侵食地帯にあるはずだ。戦闘員と同行してくれ。","ENG":"The installation site will be in a Corrupted Area, so bring combat personnel with you.","TWN":"設置地點位於侵蝕地區，也請帶上戰鬥人員。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"저도 따라갈게요.","JPN":"私も一緒に行きます。","ENG":"I'll come along too.","TWN":"我也一起去。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"여려 보이긴 해도, 제법 유능한 전투원이거든요.","JPN":"弱そうに見えるかもしれませんけど、これでもかなり有能な戦闘員ですから。","ENG":"I may look delicate, but I'm actually quite a capable fighter.","TWN":"雖然我看起來有點柔弱，但我是相當能幹的戰鬥人員。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"제법... 그래보이는구려.","JPN":"かなり……強そうであるな。","ENG":"Quite... so it seems.","TWN":"確實……看起來是如此。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"근처 정비동 격납고에 쓸만한 자재들이 많이 있습니다.","JPN":"近くの警備棟の格納庫に使えそうな資材がたくさんあります。","ENG":"There are plenty of usable materials in the maintenance hangar nearby.","TWN":"附近維修棟的機庫有很多可用的材料。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DAD_NPC_ANAP_NULL","text":{"KOREA":"저는 필요한 리스트를 추려서 수송부에 연락을 취할 테니, 여러분은 먼저 출발하세요.","JPN":"俺は必要な物のリストを絞って輸送部に連絡しますので、皆さんは先に出発してください。","ENG":"I'll put together a list of what we need and contact transport, so you all head out first.","TWN":"我會整理需要的清單並聯絡運輸部，你們先出發吧。"},"stage":{"bg":"DORMITORY_1","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DAD_NPC_ANAP_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"구태여 날 안고 있을 필요가 있는 거요?","JPN":"あえて某を抱えていく必要があるのだろうか？","ENG":"Is there really any need for you to keep holding me?","TWN":"有必要一直抱著我嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"앉을 자리가 부족해서 이렇게 하는 게 최선인 걸요?","JPN":"座席が少ないですし、これがベストだと思います。","ENG":"There aren't enough seats, so this is the best option.","TWN":"因為座位不夠，這樣是最好的辦法。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L46_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"설마, 나는 기계몸이니 짐칸에 실어도 괜찮다- 같은 고리타분한 말씀을 하려는 건 아니죠?","JPN":"まさか、「某は機械の体をしているから荷物置き場に置いてもいい」みたいなお堅いこと言おうとしているのではないでしょうね？","ENG":"You're not about to say something cliche like, \\"I have a machine body, so you can just toss me in the cargo hold,\\" are you?","TWN":"你該不會想說「反正我是機械身體，放在貨艙也沒關係」這種老掉牙的話吧？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L47_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L48_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"하담 씨에게 하나 물어봐도 될까요?","JPN":"カタンさんに、一つ聞いてもいいかしら。","ENG":"May I ask you something, Ha Dam?","TWN":"夏垣，我可以問你一個問題嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...듣고 있네.","JPN":"……続けたまえ。","ENG":"...I'm listening.","TWN":"……我在聽。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신은 어쩌다 그 <color=#ffd34c>우물</color>이란 걸 만들게 된 거죠?","JPN":"あなたはどうしてその<color=#ffd34c>イド</color>とやらを作ることになったのですか？","ENG":"How did you end up creating this <color=#ffd34c>Well</color> in the first place?","TWN":"你為什麼會製作那個叫<color=#ffd34c>井</color>的裝置呢？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"과거로 돌아가, 과거를 바로잡고자 했소.","JPN":"過去に戻り、過去を正そうとしたのだ。","ENG":"I wished to return to the past and set it right.","TWN":"為了回到過去、修正過去。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"허나 틀린 생각이었지. 바로 잡아야 했던 것은 과거가 아닌 본인의 어수선한 마음이었으니.","JPN":"だが、それは間違っていた。正すべきは過去ではなく、某の乱れた心だったゆえ。","ENG":"But that was the wrong idea. What needed setting right was not the past, but my own troubled heart.","TWN":"但那是錯誤的想法。真正需要修正的不是過去，而是我自己混亂不安的心。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"비관적으로 말씀하시는 걸 보니, 잘 풀리지 않았나 봐요.","JPN":"悲観的におっしゃるところを見ると、うまくいかなかったのですね。","ENG":"The way you say that sounds pretty pessimistic. I take it things didn't work out very well?","TWN":"你說得很悲觀，看來事情沒有成功。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"아니. 그럼에도 결과적으로는... 모든 것이 잘 되었소.","JPN":"いや。それでも結果的には……すべてがうまくいった。","ENG":"No. Even so, in the end... everything turned out okay.","TWN":"不。即便如此，從結果來看……一切都算順利。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"육신은 건사하지 못했으나, 많은 이들의 부단한 노력 덕에 오늘을 살아갈 기회도 얻었지.","JPN":"肉体は守れなかったが、多くの者の弛まぬ努力により今日を生きる機会を与えられたのだ。","ENG":"I failed to preserve my body, but thanks to the tireless efforts of many people, I was given the chance to live on into today.","TWN":"雖然失去肉身，但多虧許多人不斷的努力，我也得以活到今天。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이런 기계 몸에 갇힌 신세가 되었는데도, 정말 잘 된 게 맞나요?","JPN":"こんな機械の体になっても、本当によかったと言えるのですか？","ENG":"Even though you ended up trapped in a machine body like this, did things really turn out okay?","TWN":"就算被困在機械身體裡，也算順利嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"바라는 모든 것을 이룰 수는 없으나 내가 가장 바라는 것 하나를 이루었다네.","JPN":"望むすべてを叶えることはできなくとも、某が最も望んでいた一つだけは叶えることができたゆえ。","ENG":"I couldn't achieve everything I wanted, but I did achieve the one thing I wanted most.","TWN":"人不可能實現所有願望，但我實現了自己最想實現的一件事。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"그러니 단연코 후회는 없소.","JPN":"後悔はない。","ENG":"So I have no regrets. None at all.","TWN":"所以我絕對不會後悔。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"자기 자신보다 더 소중한 게 있다니.","JPN":"自分自身より大切なものがあるなんて。","ENG":"To have something more precious than yourself.","TWN":"居然有比自己還重要的東西。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"만약 그 소중한 게 사람이었다면, 그 사람은 정말 행복하겠어요.","JPN":"もしそれが人なら、その人は本当に幸せでしょうね。","ENG":"If that precious thing were a person, then that person must be very happy.","TWN":"如果那個重要的東西是某個人的話，那個人一定很幸福。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"지금이 행복하오?","JPN":"今、幸せか？","ENG":"Are you happy now?","TWN":"你現在幸福嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"네, 행복해요.","JPN":"はい、幸せです。","ENG":"Yes, I am.","TWN":"嗯，我很幸福。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"이 행복이 얼마나 갈지는 아무래도 좋을 만큼, 지금의 하루하루가 소중하게 느껴진답니다.","JPN":"この幸せがいつまで続くかなんてどうでもいいと思えるほど、今の毎日が大切なんです。","ENG":"So much so that it doesn't even matter how long this happiness lasts. Each day I have right now feels precious.","TWN":"幸福能維持多久其實無所謂，因為現在的每一天都讓我覺得非常珍貴。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...그것 참.","JPN":"……それは、それは。","ENG":"...Well now.","TWN":"……是嗎。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L18_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"듣기에 좋은 말이구려.","JPN":"いい話を聞かせてもらった。","ENG":"That's good to hear.","TWN":"這句話真動聽。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"여러분은 미래에서 온 건가요?","JPN":"皆さんは未来から来られたのですか？","ENG":"Are you all from the future?","TWN":"你們來自未來嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...정확히는 20년 뒤요.","JPN":"……正確には20年後だ。","ENG":"...To be precise, from twenty years ahead.","TWN":"……確切來說是20年後。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"후후, 과거 사람한테 그렇게 순순히 미래여행자란 사실을 밝혀도 되는 건가요?","JPN":"ふふ、過去の人に素直に自分が未来からの旅行者だってことを話してもいいのですか？","ENG":"Haha, is it really okay to admit so readily to someone from the past that you're a time traveler from the future?","TWN":"呵呵，對過去的人坦承自己是時間旅行者，真的沒問題嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"안전장치가 있거든. 우리가 돌아가면 이곳에서의 일은 없던 일이 되는 셈이 된다네.","JPN":"安全装置があるのだ。我らが戻れば、ここでの出来事はなかったことになる。","ENG":"There's a safeguard. Once we return, it'll be as if nothing that happened here ever happened.","TWN":"我們有安全裝置。等我們回去後，這裡發生的一切就會變成沒有發生過。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"20년 뒤의 당신은 말투가 많이 변했네요.","JPN":"20年後のあなたは、口調がずいぶん変わったんですね。","ENG":"You speak very differently twenty years from now.","TWN":"20年後的你，說話方式變了很多呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...무슨 소린지 모르겠구려.","JPN":"……何のことやら分からんな。","ENG":"...I've no idea what you mean.","TWN":"……我不懂你在說什麼。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그 기계 뒤에 숨어있어도, 말투가 변해도, 저는 다 알 수 있어요. 당신은 당신이니까.","JPN":"その機械の裏に隠れていても、口調が変わっても、私には分かります。あなたはあなたですもの。","ENG":"Even if you hide behind that machine, even if the way you speak has changed, I can still tell. You're still you.","TWN":"就算躲在那個機械身體後面、說話方式變了，我也知道是你。因為你就是你。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"그런데 절 보고 반기기는커녕 정체를 숨는 걸 보면, 미래의 당신은 절 별로 좋아하지 않는 모양이네요.","JPN":"でも、私を見て嬉しく思うどころか正体を隠すところを見ると、未来のあなたは私のことがあまり好きではないようですね。","ENG":"But instead of being happy to see me, you're hiding who you are, so I guess the future you doesn't like me very much.","TWN":"但看你見到我不但不開心，反而還隱藏身分，看來未來的你似乎不太喜歡我呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"미래에도 우리 두 사람이 행복한지 물어보고 싶었을 뿐인데.","JPN":"未来でも二人は幸せなのか聞きたかっただけなのに。","ENG":"I only wanted to ask whether the two of us are still happy together in the future.","TWN":"我只是想問你，未來的我們是不是依舊過得幸福。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"...난 그대가 아는 주한이 아닐세. 내가 꿈에서 보았던 여인이 그대가 아니듯 말이지.","JPN":"……某はそなたの知っているシスイではない。某が夢で見た女がそなたではないように。","ENG":"...I am not the Joo Han you know. Just as the woman I saw in my dream was not you.","TWN":"……我並不是所認識的周翰，就像在我夢裡見到的那位女子也不是你一樣。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L29_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"꿈에서 본... 여인?","JPN":"夢で見た……女？","ENG":"The woman from your dream...?","TWN":"夢裡見到的……女子？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"어휴- 아는 척하기 싫으면 어려운 소리 말고, 이것 하나만 대답해줘요.","JPN":"はあ……知ったかぶりしたくないのなら難しいこと言ってないで、これだけ答えてください。","ENG":"Ugh. If you don't want to act like you know me, then forget the cryptic talk and just answer this one thing.","TWN":"唉—如果不想裝熟，就別說那些難懂的話了，只要回答我一個問題就好。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"당신과 내가 미래에도 행복하게 지내고 있는지.","JPN":"あなたと私が未来でも幸せに暮らしているのか。","ENG":"Are you and I still happy together in the future?","TWN":"你和我，在未來是不是依然過得幸福。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_ANAP_GAP","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"지난 긴 세월 동안 난 많은 것을 배웠지만, 내가 그대에게 남기고픈 말은 하나요.","JPN":"これまでの長い年月の間にたくさんのことを学んできたが、某がそなたに残したい言葉は一つだ。","ENG":"Over the long years, I have learned many things, but there is only one thing I wish to leave you with.","TWN":"在漫長的歲月裡，我學會了很多事，但有一句話想留給你。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"다가올 미래를 염려하지 말고, 오늘날 곁에 머무는 행복을 기꺼이 누리시게.","JPN":"迫りくる未来を憂うのではなく、今日そなたのそばにある幸福を存分に味わいたまえ。","ENG":"Don't worry about the future to come, and gladly cherish the happiness that stays by your side today.","TWN":"不要對尚未到來的未來感到憂慮，好好享受今天陪伴在你身邊的幸福。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"말을 참 어렵고, 멋지게 하네요.","JPN":"まったく、言葉を難しく、それでいて格好よく使うんだから。","ENG":"You really do make things sound complicated and elegant.","TWN":"說的話真是又難懂又帥氣。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L42_1","type":"dialog","speaker":"YEONHWA_ADMIN_NULL_NULL","text":{"KOREA":"누가 서생 아니랄까봐.","JPN":"さすがは書生。","ENG":"As expected of Seosaeng.","TWN":"怕別人不知道你是書生。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L44_1","type":"dialog","speaker":"SEOSAENG_ATELIER_ANAP_GAP","text":{"KOREA":"훗.","JPN":"ふっ。","ENG":"Heh.","TWN":"呵。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_09","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOSAENG_ATELIER_NULL_NULL","face":"UNIT_LAUGH"},"R":{"char_id":"YEONHWA_ADMIN_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};